    if (i === 0) {
        t = parseInt(line);
        i++;
    } else if (i === 1) {
        n = parseInt(line);
        i++;
    } else {
        arr = line.split(' ').map(num => parseInt(num));
        arr.sort((a, b) => a - b);
        console.log(arr[arr.length - 1] - arr[0]);
        i = 1;
        t--;
        if (t === 0) {
            readline.close();
        }
    }
});

